import os
from flask import Flask, send_file, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)
UPLOAD_FOLDER = '/path/to/upload/directory'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

@app.route('/files', methods=['GET'])
def list_files():
    relative_path = request.args.get('path', '')
    full_path = os.path.join(app.config['UPLOAD_FOLDER'], relative_path)
    full_path = os.path.normpath(full_path)
    if os.path.commonprefix([full_path, app.config['UPLOAD_FOLDER']]) != app.config['UPLOAD_FOLDER']:
        return "Access denied", 403
    if os.path.isdir(full_path):
        return jsonify(os.listdir(full_path))
    else:
        return "Not a directory", 400

@app.route('/files', methods=['POST'])
def download_file():
    relative_path = request.args.get('path', '')
    full_path = os.path.join(app.config['UPLOAD_FOLDER'], relative_path)
    full_path = os.path.normpath(full_path)
    if os.path.commonprefix([full_path, app.config['UPLOAD_FOLDER']]) != app.config['UPLOAD_FOLDER']:
        return "Access denied", 403
    if os.path.isfile(full_path):
        return send_file(full_path, as_attachment=True)
    else:
        return "Not a file", 400

@app.route('/fileinfo', methods=['GET'])
def file_info():
    relative_path = request.args.get('path', '')
    full_path = os.path.join(app.config['UPLOAD_FOLDER'], relative_path)
    full_path = os.path.normpath(full_path)
    if os.path.commonprefix([full_path, app.config['UPLOAD_FOLDER']]) != app.config['UPLOAD_FOLDER']:
        return "Access denied", 403
    if os.path.exists(full_path):
        return jsonify({
            'size': os.path.getsize(full_path),
            'last_modified': os.path.getmtime(full_path),
            'created': os.path.getctime(full_path)
        })
    else:
        return "File not found", 404

